using System;
using UnityEngine;
using System.Collections.Generic;
using System.Security.Cryptography;
using System.Text;

public class PlayerStats : MonoBehaviour
{
    [Header("Player Stats")]
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 1000;
    public int damage = 10;
    
    [Header("Shop Items")]
    public List<ShopItem> shopItems = new List<ShopItem>();
    
    private string secretKey = "your_secret_key_here"; // Should be stored securely
    
    [Serializable]
    public class ShopItem
    {
        public string itemName;
        public int price;
        public int damageBoost;
        public int healthBoost;
        public int currencyBoost;
        public bool isPurchased = false;
    }
    
    private void Start()
    {
        ValidateStats();
    }
    
    private void ValidateStats()
    {
        health = Mathf.Clamp(health, 0, maxHealth);
        currency = Mathf.Max(0, currency);
        damage = Mathf.Max(1, damage);
    }
    
    public void ApplyDamage(int damageAmount)
    {
        if (damageAmount <= 0) return;
        
        int actualDamage = Mathf.Max(0, damageAmount - CalculateDefense());
        health -= actualDamage;
        ValidateStats();
        
        if (health <= 0)
        {
            OnPlayerDeath();
        }
    }
    
    private int CalculateDefense()
    {
        // Simple defense calculation based on health
        return Mathf.Max(0, maxHealth - health) / 10;
    }
    
    private void OnPlayerDeath()
    {
        // Handle player death logic
        Debug.Log("Player has died!");
    }
    
    public bool PurchaseItem(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= shopItems.Count) return false;
        
        ShopItem item = shopItems[itemIndex];
        
        if (item.isPurchased) return false;
        
        if (currency >= item.price)
        {
            currency -= item.price;
            item.isPurchased = true;
            
            if (item.damageBoost > 0)
            {
                damage += item.damageBoost;
            }
            
            if (item.healthBoost > 0)
            {
                maxHealth += item.healthBoost;
                health += item.healthBoost;
            }
            
            if (item.currencyBoost > 0)
            {
                currency += item.currencyBoost;
            }
            
            ValidateStats();
            return true;
        }
        
        return false;
    }
    
    public bool CanAffordItem(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= shopItems.Count) return false;
        
        ShopItem item = shopItems[itemIndex];
        return currency >= item.price;
    }
    
    public int CalculateDamage()
    {
        return damage;
    }
    
    public string GenerateSecureToken()
    {
        // Generate a secure token for validation
        string data = $"{Time.time}_{currency}_{health}";
        using (SHA256 sha256Hash = SHA256.Create())
        {
            byte[] dataBytes = sha256Hash.ComputeHash(Encoding.UTF8.GetBytes(data + secretKey));
            StringBuilder builder = new StringBuilder();
            for (int i = 0; i < dataBytes.Length; i++)
            {
                builder.Append(dataBytes[i].ToString("x2"));
            }
            return builder.ToString();
        }
    }
    
    public bool ValidateToken(string token)
    {
        // Validate the token to prevent cheating
        string expectedToken = GenerateSecureToken();
        return token == expectedToken;
    }
    
    public void ResetPlayerStats()
    {
        health = maxHealth;
        currency = 1000;
        damage = 10;
        
        foreach (ShopItem item in shopItems)
        {
            item.isPurchased = false;
        }
    }
}